using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Exploration of numbers, structures, and patterns." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Understanding the fundamental laws of nature and the universe." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Literature, writing, and critical analysis of texts." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and their impact on the present." },
            new() { Id = 6, Code = "BIO", Name = "Biology", Description = "The science of life and living organisms." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Email = "achen@university.edu", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 peer-reviewed papers and leads the university's AI research lab." },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor", Email = "rmartinez@university.edu", Bio = "Dr. Martinez focuses on abstract algebra and number theory. He received the university's Distinguished Teaching Award in 2023." },
            new() { Id = 3, Name = "Dr. Sarah Thompson", Title = "Professor", Email = "sthompson@university.edu", Bio = "Dr. Thompson is a condensed matter physicist whose research explores quantum materials. She is a fellow of the American Physical Society." },
            new() { Id = 4, Name = "Prof. James O'Brien", Title = "Associate Professor", Email = "jobrien@university.edu", Bio = "Prof. O'Brien is a published novelist and literary critic specializing in 20th-century American fiction." },
            new() { Id = 5, Name = "Dr. Maria Gonzalez", Title = "Assistant Professor", Email = "mgonzalez@university.edu", Bio = "Dr. Gonzalez is a historian of Latin American social movements with a focus on the modern era." },
            new() { Id = 6, Name = "Dr. David Park", Title = "Professor", Email = "dpark@university.edu", Bio = "Dr. Park researches molecular genetics and has contributed to breakthroughs in gene therapy techniques." },
            new() { Id = 7, Name = "Dr. Emily Watson", Title = "Lecturer", Email = "ewatson@university.edu", Bio = "Dr. Watson specializes in software engineering and distributed systems. She spent 10 years in industry before joining academia." },
            new() { Id = 8, Name = "Dr. Michael Rivera", Title = "Professor", Email = "mrivera@university.edu", Bio = "Dr. Rivera is a statistician whose work bridges applied mathematics and data science. He consults for several Fortune 500 companies." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "An introductory course covering fundamental programming concepts, data types, control structures, and basic algorithms using Python.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 201", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 120, CurrentEnrollment = 98 },
            new() { Id = 2, Code = "CS 301", Title = "Data Structures and Algorithms", Description = "In-depth study of data structures (trees, graphs, hash tables) and algorithm design techniques including divide-and-conquer, dynamic programming, and greedy methods.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Science Hall 305", DepartmentId = 1, InstructorId = 1, IsFeatured = false, MaxEnrollment = 60, CurrentEnrollment = 55 },
            new() { Id = 3, Code = "CS 450", Title = "Artificial Intelligence", Description = "Covers core AI topics: search algorithms, knowledge representation, machine learning fundamentals, neural networks, and natural language processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Location = "Tech Center 110", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 45, CurrentEnrollment = 42 },
            new() { Id = 4, Code = "CS 210", Title = "Software Engineering", Description = "Principles of software development including requirements analysis, design patterns, testing strategies, version control, and agile methodologies.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Location = "Tech Center 205", DepartmentId = 1, InstructorId = 7, IsFeatured = false, MaxEnrollment = 50, CurrentEnrollment = 38 },
            new() { Id = 5, Code = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to systems of equations.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Mathematics Bldg 102", DepartmentId = 2, InstructorId = 2, IsFeatured = true, MaxEnrollment = 80, CurrentEnrollment = 72 },
            new() { Id = 6, Code = "MATH 310", Title = "Abstract Algebra", Description = "Introduction to algebraic structures: groups, rings, and fields with emphasis on proof techniques.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", Location = "Mathematics Bldg 204", DepartmentId = 2, InstructorId = 2, IsFeatured = false, MaxEnrollment = 35, CurrentEnrollment = 28 },
