@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Courses – University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or keyword…" />
    </div>
    <div class="col-md-4">
        <select name="dept" class="form-select">
            <option value="">All Departments</option>
            @foreach (var d in departments)
            {
                if (d.Id == Dept)
                {
                    <option value="@d.Id" selected>@d.Name</option>
                }
                else
                {
                    <option value="@d.Id">@d.Name</option>
                }
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted">Showing @courses.Count course(s)</p>

    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                var dept = departments.First(d => d.Id == course.DepartmentId);
                <tr>
                    <td><strong>@course.Code</strong></td>
                    <td>@course.Title</td>
                    <td>@dept.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery(Name = "search")]
    public string? Search { get; set; }

    [SupplyParameterFromQuery(Name = "dept")]
    public int? Dept { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetAllDepartments();
        courses = Catalog.SearchCourses(Search, Dept);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found") – University Course Catalog</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="departments/@department?.Id">@department?.Name</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code – @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule &amp; Location</h4>
            <table class="table">
                <tr><th style="width:150px">Schedule</th><td>@course.Schedule</td></tr>
                <tr><th>Location</th><td>@course.Location</td></tr>
                <tr><th>Credits</th><td>@course.Credits</td></tr>
            </table>

            <h4 class="mt-4">Enrollment</h4>
            <div class="progress mb-2" style="height: 24px;">
                @{ var pct = (int)((double)course.CurrentEnrollment / course.MaxEnrollment * 100); }
                <div class="progress-bar @(pct > 90 ? "bg-danger" : "bg-success")" role="progressbar"
                     style="width: @(pct)%;" aria-valuenow="@course.CurrentEnrollment"
                     aria-valuemin="0" aria-valuemax="@course.MaxEnrollment">
                    @course.CurrentEnrollment / @course.MaxEnrollment
                </div>
            </div>
            <p class="text-muted">@(course.MaxEnrollment - course.CurrentEnrollment) seat(s) remaining</p>

            <a href="enroll?courseId=@course.Id" class="btn btn-primary">Request Enrollment</a>
        </div>

        <div class="col-md-4">
            @if (instructor is not null)
            {
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Instructor</h5>
                        <h6>@instructor.Name</h6>
                        <p class="text-muted mb-1">@instructor.Title</p>
                        <p class="mb-2"><a href="mailto:@instructor.Email">@instructor.Email</a></p>
                        <hr />
                        <p class="small">@instructor.Bio</p>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;
    private Department? department;
    private Instructor? instructor;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
        if (course is not null)
        {
            department = Catalog.GetDepartment(course.DepartmentId);
            instructor = Catalog.GetInstructor(course.InstructorId);
        }
    }
}

