@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Home – University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Browse our departments and courses for the current semester. Find the right classes and submit your enrollment request online.</p>

<hr />

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        var dept = Catalog.GetAllDepartments().First(d => d.Id == course.DepartmentId);
        <div class="col-md-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Description[..Math.Min(course.Description.Length, 120)]…</p>
                    <span class="badge bg-primary me-1">@course.Credits credits</span>
                    <span class="badge bg-secondary">@dept.Name</span>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<hr />

<h2>Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text text-muted">@dept.Description</p>
                    <a href="departments/@dept.Id" class="btn btn-sm btn-outline-secondary">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetAllDepartments();
    }
}

