@page "/departments"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Departments – University Course Catalog</PageTitle>

<h1>Departments</h1>

<div class="row">
    @foreach (var dept in departments)
    {
        var courseCount = Catalog.GetCoursesByDepartment(dept.Id).Count;
        <div class="col-md-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <span class="badge bg-secondary mb-2">@dept.Code</span>
                    <p class="card-text">@dept.Description</p>
                    <p class="text-muted small">@courseCount course(s) offered</p>
                </div>
                <div class="card-footer">
                    <a href="departments/@dept.Id" class="btn btn-sm btn-outline-primary">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetAllDepartments();
    }
}

@page "/departments/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>@(department?.Name ?? "Department Not Found") – University Course Catalog</PageTitle>

@if (department is null)
{
