                    <th>Title</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td><strong>@course.Code</strong></td>
                        <td>@course.Title</td>
                        <td>@course.Credits</td>
                        <td>@course.Schedule</td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Department? department;
    private List<Course> courses = new();

    protected override void OnInitialized()
    {
        department = Catalog.GetDepartment(Id);
        if (department is not null)
        {
            courses = Catalog.GetCoursesByDepartment(department.Id);
        }
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request – University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course. You will receive confirmation via your university email.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@model.StudentName</strong>. Your enrollment request for
            <strong>@(selectedCourse?.Code) – @(selectedCourse?.Title)</strong> has been received.
            You will receive a confirmation at your university email address.</p>
        <a href="enroll" class="btn btn-outline-primary">Submit Another Request</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" id="studentName" name="model.StudentName" value="@model.StudentName"
                           class="form-control" required maxlength="100" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" id="studentId" name="model.StudentId" value="@model.StudentId"
                           class="form-control" required pattern="[A-Za-z0-9]{6,12}"
                           title="6–12 alphanumeric characters" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select id="courseId" name="model.CourseId" class="form-select" required>
                        <option value="">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            if (course.Id == model.CourseId)
                            {
                                <option value="@course.Id" selected>@course.Code – @course.Title (@course.Credits cr)</option>
                            }
                            else
                            {
                                <option value="@course.Id">@course.Code – @course.Title (@course.Credits cr)</option>
                            }
                        }
                    </select>
                </div>

                <div class="mb-3">
                    <label for="comments" class="form-label">Comments (optional)</label>
                    <textarea id="comments" name="model.Comments" class="form-control" rows="3"
                              maxlength="500">@model.Comments</textarea>
                </div>

                <button type="submit" class="btn btn-primary">Submit Request</button>
                <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    private List<Course> courses = new();
    private Course? selectedCourse;
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();

        if (PreselectedCourseId.HasValue && model.CourseId == 0)
        {
            model.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        selectedCourse = Catalog.GetCourse(model.CourseId);
        Catalog.SubmitEnrollmentRequest(model);
        submitted = true;
    }
}

